  if (hasServerFile || hasApi || hasAppRouter) return false;

  const hasExports = packageJson.exports || packageJson.main || packageJson.module || packageJson.types || packageJson.browser;
  if (!hasExports) return false;

  const hasWorkspaceApps = tree.some(p => /^(apps|services|workers)\/[^/]+\/package\.json$/i.test(p));
